  1→import { useMemo } from "react";
  2→import { Plus, ChevronRight, ChevronDown, GitPullRequest } from "lucide-react";
  3→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
  4→import { SidebarMenuItem } from "@/components/ui/sidebar";
  5→import { Collapsible, CollapsibleTrigger } from "@/components/ui/collapsible";
  6→import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
  7→import { cn } from "@/shared/lib/utils";
  8→import { useUnreadStore } from "@/features/session/store/unreadStore";
  9→import { useWorkspaceLayoutStore } from "@/features/workspace/store/workspaceLayoutStore";
 10→import { getCleanRepoName, splitByRecency } from "../lib/utils";
 11→import { sortByStatusPriority } from "../lib/status";
 12→import { useSidebarStore } from "../store/sidebarStore";
 13→import type { RepositoryItemProps } from "../model/types";
 14→import type { Workspace, DiffStats, RepoGroup } from "@/shared/types";
 15→import type { WorkspaceStatus } from "@shared/enums";
 16→import { WorkspaceItem } from "./WorkspaceItem";
 17→import { RepoAvatar } from "./RepoAvatar";
