 20→
 21→/** Check if a git remote URL points to GitHub */
 22→function isGitHubUrl(url: string | null | undefined): boolean {
 23→  return !!url && url.includes("github.com");
 24→}
 25→
 26→/**
 27→ * RepositoryItem — V2: Jony Ive
 28→ *
 29→ * Layout:
 30→ *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 31→ *     └── [+ New workspace]
 32→ *     └── WorkspaceItem[]
 33→ *
 34→ * The repo header uses text-secondary (B0B0B0) 14px medium.
 35→ * Action icons: text-muted (#787878), appear on hover.
 36→ */
 37→export function RepositoryItem({
 38→  repository,
 39→  isCollapsed,
 40→  selectedWorkspaceId,
 41→  onToggleCollapse,
 42→  onWorkspaceClick,
 43→  onNewWorkspace,
 44→  onNewWorkspaceFromGitHub,
 45→  onArchive,
 46→  onStatusChange,
 47→  diffStatsMap,
 48→  sidebarExpanded,
 49→}: RepositoryItemProps) {
 50→  const reduceMotion = useReducedMotion();
 51→  const repoName = getCleanRepoName(repository.repo_name);
 52→
 53→  // Build set of workspace IDs that have any unread tab session,
 54→  // checking all tab sessions (matching WorkspaceItem's logic).
 55→  const unreadMap = useUnreadStore((s) => s.unreadSessionIds);
 56→  const layouts = useWorkspaceLayoutStore((s) => s.layouts);
 57→  const unreadWorkspaceIds = useMemo(() => {
 58→    const ids = new Set<string>();
 59→    for (const ws of repository.workspaces) {
 60→      const tabIds = layouts[ws.id]?.chatTabSessionIds;
 61→      const sessionIds = tabIds?.length
 62→        ? tabIds
 63→        : ws.current_session_id
 64→          ? [ws.current_session_id]
 65→          : [];
 66→      if (sessionIds.some((sid) => unreadMap[sid])) ids.add(ws.id);
 67→    }
 68→    return ids.size > 0 ? ids : undefined;
 69→  }, [repository.workspaces, unreadMap, layouts]);
 70→  // Detect the deus repo by clean name
 71→  const isDeus = repoName === "deus";
 72→  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;
 73→
 74→  return (
 75→    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
 76→      <SidebarMenuItem
 77→        data-state={isCollapsed ? "closed" : "open"}
 78→        className="group/repository-item relative"
 79→      >
 80→        <CollapsibleTrigger asChild>
 81→          <SidebarRow
 82→            variant="repo"
 83→            role="button"
 84→            aria-label={`Toggle ${repoName} workspaces`}
 85→            className="cursor-grab"
 86→          >
 87→            <SidebarRowMain className="gap-2">
 88→              <div className="relative flex-shrink-0">
 89→                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
 90→                  <RepoAvatar repoName={repository.repo_name} />
 91→                </div>
 92→                <ChevronRight
 93→                  className={cn(
 94→                    "absolute inset-0 m-auto h-4 w-4",
 95→                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
 96→                    !isCollapsed && "rotate-90"
 97→                  )}
 98→                />
 99→              </div>
100→              <span className="text-text-secondary truncate text-sm font-medium">{repoName}</span>
101→              {workspaceCount > 0 && (
102→                <span className="text-text-muted text-xs tabular-nums">{workspaceCount}</span>
103→              )}
104→            </SidebarRowMain>
105→            {sidebarExpanded && (
106→              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
107→                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
108→                  <Tooltip>
109→                    <TooltipTrigger asChild>
110→                      <button
111→                        type="button"
112→                        aria-label={`New workspace from PR or branch in ${repoName}`}
113→                        onClick={(e) => {
114→                          e.stopPropagation();
115→                          onNewWorkspaceFromGitHub(repository.repo_id);
116→                        }}
117→                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
118→                      >
119→                        <GitPullRequest className="h-4 w-4" />
120→                      </button>
121→                    </TooltipTrigger>
122→                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
123→                  </Tooltip>
124→                )}
125→                <Tooltip>
126→                  <TooltipTrigger asChild>
127→                    <button
128→                      type="button"
129→                      aria-label={`New workspace in ${repoName}`}
130→                      onClick={(e) => {
131→                        e.stopPropagation();
132→                        onNewWorkspace(repository.repo_id);
133→                      }}
134→                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
135→                    >
136→                      <Plus className="h-4 w-4" />
137→                    </button>
138→                  </TooltipTrigger>
139→                  <TooltipContent side="bottom">New workspace</TooltipContent>
140→                </Tooltip>
141→              </SidebarRowRight>
142→            )}
143→          </SidebarRow>
144→        </CollapsibleTrigger>
145→      </SidebarMenuItem>
146→      <AnimatePresence initial={false}>
147→        {!isCollapsed && (
148→          <m.ul
149→            key="workspace-list"
150→            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
151→            animate={{ height: "auto", opacity: 1 }}
152→            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
153→            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
154→            className="flex min-w-0 flex-col overflow-hidden"
155→          >
156→            {sidebarExpanded && (
157→              <RepositoryWorkspaceList
158→                repository={repository}
159→                isDeus={isDeus}
160→                selectedWorkspaceId={selectedWorkspaceId}
161→                unreadWorkspaceIds={unreadWorkspaceIds}
162→                diffStatsMap={diffStatsMap}
163→                reduceMotion={reduceMotion}
164→                onNewWorkspace={onNewWorkspace}
165→                onWorkspaceClick={onWorkspaceClick}
166→                onArchive={onArchive}
167→                onStatusChange={onStatusChange}
168→              />
169→            )}
170→          </m.ul>
171→        )}
172→      </AnimatePresence>
173→    </Collapsible>
174→  );
175→}
176→
177→// ── Inner list with stale-workspace collapsing ───────────────────────────
178→
179→interface RepositoryWorkspaceListProps {
180→  repository: RepoGroup;
181→  isDeus: boolean;
182→  selectedWorkspaceId: string | null;
183→  unreadWorkspaceIds?: Set<string>;
184→  diffStatsMap?: Record<string, DiffStats>;
185→  reduceMotion: boolean | null;
186→  onNewWorkspace: (repoId?: string) => void;
187→  onWorkspaceClick: (workspace: Workspace) => void;
188→  onArchive?: (workspaceId: string) => void;
189→  onStatusChange?: (workspaceId: string, status: WorkspaceStatus) => void;
190→}
191→
192→function RepositoryWorkspaceList({
193→  repository,
194→  isDeus,
195→  selectedWorkspaceId,
196→  unreadWorkspaceIds,
197→  diffStatsMap,
198→  reduceMotion,
199→  onNewWorkspace,
200→  onWorkspaceClick,
201→  onArchive,
202→  onStatusChange,
203→}: RepositoryWorkspaceListProps) {
204→  const isExpanded = useSidebarStore((s) => s.expandedOldWorkspaces.has(repository.repo_id));
205→  const toggleOldWorkspaces = useSidebarStore((s) => s.toggleOldWorkspaces);
206→
207→  const sortedWorkspaces = sortByStatusPriority(
208→    repository.workspaces.filter((w) => w.state !== "archived"),
209→    unreadWorkspaceIds
210→  );
211→
212→  const [visible, stale] = splitByRecency(sortedWorkspaces, selectedWorkspaceId);
213→  const hasStale = stale.length > 0;
214→  const displayedWorkspaces = hasStale && !isExpanded ? visible : sortedWorkspaces;
215→
216→  return (
217→    <>
218→      {isDeus && (
219→        <m.li
220→          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
221→          animate={{ opacity: 1, y: 0 }}
222→          transition={{
223→            duration: 0.22,
224→            ease: [0.165, 0.84, 0.44, 1],
225→            delay: reduceMotion ? 0 : 0.02,
226→          }}
227→        >
228→          <DeusRepositoryBanner onNewWorkspace={() => onNewWorkspace(repository.repo_id)} />
229→        </m.li>
230→      )}
231→
232→      {sortedWorkspaces.length === 0 && (
233→        <m.li
234→          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
235→          animate={{ opacity: 1, y: 0 }}
236→          transition={{
237→            duration: 0.18,
238→            ease: [0.165, 0.84, 0.44, 1],
239→            delay: reduceMotion ? 0 : 0.03,
240→          }}
241→        >
242→          <SidebarRow
243→            variant="action"
244→            asChild
245→            onClick={() => onNewWorkspace(repository.repo_id)}
246→            className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
247→          >
248→            <button type="button">
249→              <SidebarRowMain>
250→                <SidebarRowIconSlot>
251→                  <Plus className="h-4 w-4" />
252→                </SidebarRowIconSlot>
253→                <span className="font-normal">New workspace</span>
254→              </SidebarRowMain>
255→            </button>
256→          </SidebarRow>
257→        </m.li>
258→      )}
259→
260→      {displayedWorkspaces.map((workspace, index) => (
261→        <m.li
262→          key={workspace.id}
263→          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
264→          animate={{ opacity: 1, y: 0 }}
265→          transition={{
266→            duration: 0.18,
267→            ease: [0.165, 0.84, 0.44, 1],
268→            delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
269→          }}
270→        >
271→          <WorkspaceItem
272→            workspace={workspace}
273→            isActive={workspace.id === selectedWorkspaceId}
274→            diffStats={diffStatsMap?.[workspace.id]}
275→            onClick={onWorkspaceClick}
276→            onArchive={onArchive}
277→            onStatusChange={onStatusChange}
278→          />
279→        </m.li>
280→      ))}
281→
282→      {hasStale && (
283→        <m.li
284→          initial={reduceMotion ? false : { opacity: 0 }}
285→          animate={{ opacity: 1 }}
286→          transition={{ duration: 0.15, ease: [0.165, 0.84, 0.44, 1] }}
287→        >
288→          <SidebarRow
289→            variant="action"
290→            asChild
291→            className="text-text-muted hover:text-text-secondary w-full text-left"
292→          >
293→            <button type="button" onClick={() => toggleOldWorkspaces(repository.repo_id)}>
294→              <SidebarRowMain>
295→                <SidebarRowIconSlot>
296→                  <ChevronDown
297→                    className={cn(
298→                      "h-3.5 w-3.5 transition-transform duration-150",
299→                      isExpanded && "rotate-180"
300→                    )}
301→                  />
302→                </SidebarRowIconSlot>
303→                <span className="text-xs font-medium">
304→                  {isExpanded ? "Show less" : `Show ${stale.length} more`}
305→                </span>
306→              </SidebarRowMain>
307→            </button>
308→          </SidebarRow>
309→        </m.li>
310→      )}
311→    </>
312→  );
313→}
