  1→import React from "react";
  2→import { match } from "ts-pattern";
  3→import { Archive, Loader2 } from "lucide-react";
  4→import NumberFlow from "@number-flow/react";
  5→
  6→import { cn } from "@/shared/lib/utils";
  7→import { useWorkingDuration, formatDuration } from "@/shared/hooks";
  8→import { CircularPixelGrid } from "@/features/session/ui/CircularPixelGrid";
  9→import { useUnreadStore } from "@/features/session/store/unreadStore";
 10→import { useWorkspaceLayoutStore } from "@/features/workspace/store/workspaceLayoutStore";
 11→import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
 12→import { getWorkspaceDisplayName, getWorkspaceSecondaryText } from "../lib/utils";
 13→import type { WorkspaceItemProps } from "../model/types";
 14→import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
 15→import { WorkflowStatusIcon } from "./WorkflowStatusIcon";
 16→import { WorkspaceStatusMenu } from "./WorkspaceStatusMenu";
 17→
 18→/**
 19→ * WorkspaceItem — Sidebar workspace row
 20→ *
 21→ * Layout:  [Left (flex-1)]  [Right]
 22→ *   Left:
 23→ *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 24→ *     Row 2: [pad-left 26px] [secondary · status]
 25→ *   Right:
 26→ *     [+additions -deletions]
 27→ *
 28→ * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 29→ * Secondary line: shows slug when title is primary, otherwise just status info.
 30→ *
 31→ * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 32→ * Idle → no icon (26px indent).
 33→ *
 34→ * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 35→ */
 36→export const WorkspaceItem = React.memo(function WorkspaceItem({
 37→  workspace,
 38→  isActive,
 39→  diffStats,
 40→  onClick,
 41→  onArchive,
 42→  onStatusChange,
 43→}: WorkspaceItemProps) {
 44→  const isInitializing = workspace.state === "initializing";
 45→
 46→  // Hooks must be called unconditionally (React rules of hooks)
 47→  const { duration } = useWorkingDuration({
 48→    status: workspace.session_status,
 49→    latestMessageSentAt: workspace.latest_message_sent_at,
 50→  });
 51→
 52→  // Check all sessions in this workspace's tabs for unseen activity,
 53→  // not just current_session_id — the user may have multiple tabs open.
 54→  const tabSessionIds = useWorkspaceLayoutStore((s) => s.layouts[workspace.id]?.chatTabSessionIds);
 55→  const hasUnseenActivity = useUnreadStore((s) => {
 56→    const ids = tabSessionIds?.length
 57→      ? tabSessionIds
 58→      : workspace.current_session_id
 59→        ? [workspace.current_session_id]
 60→        : [];
 61→    return ids.some((sid) => s.unreadSessionIds[sid]);
 62→  });
 63→
 64→  // Initializing state: non-interactive row with loading animation
 65→  if (isInitializing) {
 66→    const initSecondary = getWorkspaceSecondaryText(workspace);
 67→    return (
 68→      <div className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 69→        <SidebarRow
 70→          variant="workspace"
 71→          isActive={false}
 72→          aria-label="Workspace setting up"
 73→          className="pointer-events-none"
 74→        >
 75→          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
 76→            {/* Row 1: thinking icon + display name */}
 77→            <div className="flex min-w-0 items-center gap-1.5">
 78→              <SidebarRowIconSlot>
 79→                <CircularPixelGrid variant="working" size={14} resolution={8} />
 80→              </SidebarRowIconSlot>
 81→              <span className="text-text-disabled truncate text-base font-normal">
 82→                {getWorkspaceDisplayName(workspace)}
 83→              </span>
 84→            </div>
 85→            {/* Row 2: secondary context · init stage */}
 86→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 87→              {initSecondary && (
 88→                <>
 89→                  <span className="text-text-disabled truncate text-xs">{initSecondary}</span>
 90→                  <span className="text-text-disabled text-xs">·</span>
 91→                </>
 92→              )}
 93→              <span className="text-text-muted shrink-0 text-xs">
 94→                {match(workspace.init_stage)
 95→                  .with("worktree", () => "Creating worktree...")
 96→                  .with("dependencies", () => "Installing dependencies...")
 97→                  .with("hooks", () => "Setting up environment...")
 98→                  .with("session", () => "Finalizing...")
 99→                  .otherwise(() => "Setting up...")}
100→              </span>
101→            </div>
102→          </div>
103→        </SidebarRow>
104→      </div>
105→    );
106→  }
107→
108→  const formatTime = (timestamp: string) => {
109→    const date = new Date(timestamp);
110→    const now = new Date();
111→    const diffMs = now.getTime() - date.getTime();
112→    const diffMins = Math.floor(diffMs / 60000);
113→    const diffHours = Math.floor(diffMins / 60);
114→    const diffDays = Math.floor(diffHours / 24);
115→    const diffMonths = Math.floor(diffDays / 30);
116→
117→    if (diffMins < 1) return "now";
118→    if (diffMins < 60) return `${diffMins}m ago`;
119→    if (diffHours < 24) return `${diffHours}h ago`;
120→    if (diffDays < 30) return `${diffDays}d ago`;
121→    return `${diffMonths}mo ago`;
122→  };
123→
124→  const displayStatus = getDisplayStatus(workspace, hasUnseenActivity);
125→  const statusConfig = STATUS_CONFIG[displayStatus];
126→  // Session activity icons take priority over workflow status
127→  const hasSessionIcon =
128→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
129→
130→  const isSetupRunning = workspace.setup_status === "running";
131→  const isSetupFailed = workspace.setup_status === "failed";
132→
133→  const statusTextClass = isSetupFailed
134→    ? "text-accent-red-muted"
135→    : isSetupRunning
136→      ? "text-text-muted"
137→      : match(displayStatus)
138→          .with("working", () => "text-text-tertiary")
139→          .with("unread", () => "text-text-secondary")
140→          .with("error", () => "text-accent-red-muted")
141→          .otherwise(() => "text-text-disabled");
142→
143→  const getStatusText = (): string => {
144→    if (isSetupRunning) return "Installing...";
145→    if (isSetupFailed) return "Setup failed";
146→    if (workspace.state === "archived") return "Archived";
147→    if (!workspace.session_status) return formatTime(workspace.updated_at);
148→
149→    return match(displayStatus)
150→      .with("idle", () => formatTime(workspace.updated_at))
151→      .with("unread", () => {
152→        const sessionStatus = workspace.session_status;
153→        if (sessionStatus === "needs_response" || sessionStatus === "needs_plan_response") {
154→          return "Needs response";
155→        }
156→        return "Done";
157→      })
158→      .with("working", () =>
159→        duration > 0 ? formatDuration(duration, false) : STATUS_CONFIG.working.labelActive
160→      )
161→      .with("error", () => STATUS_CONFIG.error.label)
162→      .otherwise(() => statusConfig.label);
163→  };
164→
165→  const statusText = getStatusText();
166→  const displayName = getWorkspaceDisplayName(workspace);
167→  const secondaryText = getWorkspaceSecondaryText(workspace);
168→  const showStatusDot = Boolean(secondaryText && statusText);
169→
170→  const additions = diffStats?.additions ?? 0;
171→  const deletions = diffStats?.deletions ?? 0;
172→  const hasChanges = additions > 0 || deletions > 0;
173→
174→  const handleArchive = (e: React.MouseEvent) => {
175→    e.stopPropagation();
176→    if (onArchive) {
177→      onArchive(workspace.id);
178→    }
179→  };
180→
181→  const isArchived = workspace.state === "archived";
182→  const canArchive = !isArchived && !!onArchive;
183→  const isActiveState =
184→    displayStatus === "working" || displayStatus === "unread" || displayStatus === "error";
185→
186→  return (
187→    <div>
188→      <SidebarRow
189→        variant="workspace"
190→        isActive={isActive}
191→        role="button"
192→        tabIndex={0}
193→        data-workspace-id={workspace.id}
194→        className="cursor-pointer"
195→        aria-current={isActive ? "page" : undefined}
196→        aria-label={`Workspace ${displayName}`}
197→        onClick={() => onClick(workspace)}
198→        onKeyDown={(e) => {
199→          if (e.key === " ") e.preventDefault();
200→        }}
201→        onKeyUp={(e) => {
202→          if (e.key === "Enter" || e.key === " ") onClick(workspace);
203→        }}
204→      >
205→        {/* Left: rows */}
206→        <div className="flex min-w-0 flex-1 flex-col gap-0.5">
207→          {/* Row 1: icon + display name (title > slug > branch) */}
208→          <div className="flex min-w-0 items-center gap-1.5">
209→            <WorkspaceStatusMenu
210→              currentStatus={workspace.status}
211→              onStatusChange={(status) => onStatusChange?.(workspace.id, status)}
212→            >
213→              <button
214→                type="button"
215→                onClick={(e) => e.stopPropagation()}
216→                className="flex h-5 w-5 shrink-0 items-center justify-center rounded transition-opacity hover:opacity-80"
217→                aria-label={`Status: ${workspace.status}`}
218→              >
219→                {hasSessionIcon ? (
220→                  match(displayStatus)
221→                    .with("working", () => (
222→                      <CircularPixelGrid variant="working" size={14} resolution={8} />
223→                    ))
224→                    .with("error", () => <span className="bg-accent-red h-2 w-2 rounded-full" />)
225→                    .otherwise(() => <span className="bg-accent-gold h-2 w-2 rounded-full" />)
226→                ) : (
227→                  <WorkflowStatusIcon status={workspace.status} size={14} />
228→                )}
229→              </button>
230→            </WorkspaceStatusMenu>
231→            <span
232→              className={cn(
233→                "truncate text-base",
234→                isActive
235→                  ? "text-text-primary font-medium"
236→                  : isActiveState
237→                    ? "text-text-primary font-normal"
238→                    : "text-text-tertiary font-normal"
239→              )}
240→            >
241→              {displayName}
242→            </span>
243→          </div>
244→
245→          {/* Row 2: secondary context · status */}
246→          <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
247→            {secondaryText && (
248→              <span
249→                className={cn(
250→                  "truncate text-xs",
251→                  isActiveState ? "text-text-tertiary" : "text-text-disabled"
252→                )}
253→              >
254→                {secondaryText}
255→              </span>
256→            )}
257→            {showStatusDot && (
258→              <span
259→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
260→              >
261→                ·
262→              </span>
263→            )}
264→            {statusText && (
265→              <span className={cn("flex shrink-0 items-center gap-1 text-xs", statusTextClass)}>
266→                {isSetupRunning && (
267→                  <Loader2 className="h-3 w-3 animate-spin motion-reduce:animate-none" />
268→                )}
269→                {statusText}
270→              </span>
271→            )}
272→          </div>
273→        </div>
274→
275→        {/* Right: diff stats */}
276→        {hasChanges ? (
277→          <div
278→            className={cn(
279→              "flex shrink-0 items-center gap-1.5 text-xs font-medium transition-opacity",
280→              canArchive && "group-hover/sidebar-row:opacity-0"
281→            )}
282→          >
283→            {additions > 0 && (
284→              <NumberFlow
285→                value={additions}
286→                prefix="+"
287→                className={isActive ? "text-accent-green" : "text-text-muted"}
288→              />
289→            )}
290→            {deletions > 0 && (
291→              <NumberFlow
292→                value={deletions}
293→                prefix="-"
294→                className={isActive ? "text-accent-red" : "text-text-muted"}
295→              />
296→            )}
297→          </div>
298→        ) : null}
299→
300→        {/* Archive button — hover reveal */}
301→        {canArchive ? (
302→          <button
303→            type="button"
304→            onClick={handleArchive}
305→            aria-label={`Archive workspace ${displayName}`}
306→            title="Archive workspace"
307→            className={cn(
308→              "text-text-muted hover:text-text-secondary flex h-7 w-7 items-center justify-center rounded-lg",
309→              "absolute top-1/2 right-1 -translate-y-1/2 opacity-0 transition-opacity",
310→              "group-hover/sidebar-row:opacity-100"
311→            )}
312→          >
313→            <Archive className="h-3.5 w-3.5" />
314→          </button>
315→        ) : null}
316→      </SidebarRow>
317→    </div>
318→  );
319→});
