 93→// ── Recency-based workspace splitting ────────────────────────────────────
 94→
 95→/** Minimum workspace count before stale hiding kicks in */
 96→const STALE_HIDE_MIN_WORKSPACES = 5;
 97→/** Always show at least this many workspaces (backfill from stale if needed) */
 98→const MIN_VISIBLE = 3;
 99→/** Don't bother with "Show N more" if fewer than this would be hidden */
100→const MIN_STALE_TO_HIDE = 2;
101→/** Days after which an idle workspace is considered stale */
102→const STALE_DAYS = 7;
103→
104→/**
105→ * Split workspaces into visible and stale (hidden by default).
106→ *
107→ * Rules:
108→ * - Only activates when there are >= STALE_HIDE_MIN_WORKSPACES
109→ * - Active workspaces (working, error, unread) are always visible
110→ * - The currently selected workspace is always visible
111→ * - Idle workspaces updated > STALE_DAYS ago are stale
112→ * - Always shows at least MIN_VISIBLE workspaces (backfills from stale)
113→ * - Never hides fewer than MIN_STALE_TO_HIDE (avoids "Show 1 more")
114→ *
115→ * @returns [visible, stale] — two arrays, already in the same order as input
116→ */
117→export function splitByRecency<T extends Workspace>(
118→  workspaces: T[],
119→  selectedWorkspaceId: string | null | undefined
120→): [visible: T[], stale: T[]] {
121→  if (workspaces.length < STALE_HIDE_MIN_WORKSPACES) {
122→    return [workspaces, []];
123→  }
124→
125→  const cutoff = Date.now() - STALE_DAYS * 24 * 60 * 60 * 1000;
126→  const visibleIds = new Set<string>();
127→
128→  for (const ws of workspaces) {
129→    const status = getDisplayStatus(ws);
130→    const isActive = status !== "idle";
131→    const isSelected = ws.id === selectedWorkspaceId;
132→    const isRecent = new Date(ws.updated_at).getTime() >= cutoff;
133→
134→    if (isActive || isSelected || isRecent) {
135→      visibleIds.add(ws.id);
136→    }
137→  }
138→
139→  // Backfill from stale so the repo never looks empty
140→  if (visibleIds.size < MIN_VISIBLE) {
141→    for (const ws of workspaces) {
142→      if (visibleIds.size >= MIN_VISIBLE) break;
143→      if (!visibleIds.has(ws.id)) visibleIds.add(ws.id);
144→    }
145→  }
146→
147→  // Re-derive from original array to preserve sort order
148→  const visible = workspaces.filter((ws) => visibleIds.has(ws.id));
149→  const stale = workspaces.filter((ws) => !visibleIds.has(ws.id));
150→
151→  // Don't bother hiding if only 1 would be hidden ("Show 1 more" is silly)
152→  if (stale.length < MIN_STALE_TO_HIDE) {
153→    return [workspaces, []];
154→  }
155→
156→  return [visible, stale];
157→}
