import { useMemo } from "react";
import { Plus, ChevronRight, ChevronDown, GitPullRequest } from "lucide-react";
import { AnimatePresence, m, useReducedMotion } from "framer-motion";
import { SidebarMenuItem } from "@/components/ui/sidebar";
import { Collapsible, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
import { cn } from "@/shared/lib/utils";
import { useUnreadStore } from "@/features/session/store/unreadStore";
import { useWorkspaceLayoutStore } from "@/features/workspace/store/workspaceLayoutStore";
import { getCleanRepoName, splitByRecency } from "../lib/utils";
import { sortByStatusPriority } from "../lib/status";
import { useSidebarStore } from "../store/sidebarStore";
import type { RepositoryItemProps } from "../model/types";
import type { Workspace, DiffStats, RepoGroup } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import { WorkspaceItem } from "./WorkspaceItem";
import { RepoAvatar } from "./RepoAvatar";
import { SidebarRow, SidebarRowMain, SidebarRowIconSlot, SidebarRowRight } from "./SidebarRow";
import { DeusRepositoryBanner } from "./DeusRepositoryBanner";

/** Check if a git remote URL points to GitHub */
function isGitHubUrl(url: string | null | undefined): boolean {
  return !!url && url.includes("github.com");
}

/**
 * RepositoryItem — V2: Jony Ive
 *
 * Layout:
 *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 *     └── [+ New workspace]
 *     └── WorkspaceItem[]
 *
 * The repo header uses text-secondary (B0B0B0) 14px medium.
 * Action icons: text-muted (#787878), appear on hover.
 */
export function RepositoryItem({
  repository,
  isCollapsed,
  selectedWorkspaceId,
  onToggleCollapse,
  onWorkspaceClick,
  onNewWorkspace,
  onNewWorkspaceFromGitHub,
  onArchive,
  onStatusChange,
  diffStatsMap,
  sidebarExpanded,
}: RepositoryItemProps) {
  const reduceMotion = useReducedMotion();
  const repoName = getCleanRepoName(repository.repo_name);

  // Build set of workspace IDs that have any unread tab session,
  // checking all tab sessions (matching WorkspaceItem's logic).
  const unreadMap = useUnreadStore((s) => s.unreadSessionIds);
  const layouts = useWorkspaceLayoutStore((s) => s.layouts);
  const unreadWorkspaceIds = useMemo(() => {
    const ids = new Set<string>();
    for (const ws of repository.workspaces) {
      const tabIds = layouts[ws.id]?.chatTabSessionIds;
      const sessionIds = tabIds?.length
        ? tabIds
        : ws.current_session_id
          ? [ws.current_session_id]
          : [];
      if (sessionIds.some((sid) => unreadMap[sid])) ids.add(ws.id);
    }
    return ids.size > 0 ? ids : undefined;
  }, [repository.workspaces, unreadMap, layouts]);
  // Detect the deus repo by clean name
  const isDeus = repoName === "deus";
  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;

  return (
    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
      <SidebarMenuItem
        data-state={isCollapsed ? "closed" : "open"}
        className="group/repository-item relative"
      >
        <CollapsibleTrigger asChild>
          <SidebarRow
            variant="repo"
            role="button"
            aria-label={`Toggle ${repoName} workspaces`}
            className="cursor-grab"
          >
            <SidebarRowMain className="gap-2">
              <div className="relative flex-shrink-0">
                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
                  <RepoAvatar repoName={repository.repo_name} className="h-4 w-4 rounded-sm" />
                </div>
                <ChevronRight
                  className={cn(
                    "absolute inset-0 m-auto h-3.5 w-3.5",
                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
                    !isCollapsed && "rotate-90"
                  )}
                />
              </div>
              <span className="text-text-muted truncate text-sm font-normal">{repoName}</span>
              {workspaceCount > 0 && (
                <span className="text-text-disabled text-xs tabular-nums">{workspaceCount}</span>

              )}
            </SidebarRowMain>
            {sidebarExpanded && (
              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <button
                        type="button"
                        aria-label={`New workspace from PR or branch in ${repoName}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          onNewWorkspaceFromGitHub(repository.repo_id);
                        }}
                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                      >
                        <GitPullRequest className="h-4 w-4" />
                      </button>
                    </TooltipTrigger>
                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
                  </Tooltip>
                )}
                <Tooltip>
                  <TooltipTrigger asChild>
                    <button
                      type="button"
                      aria-label={`New workspace in ${repoName}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        onNewWorkspace(repository.repo_id);
                      }}
                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                    >
                      <Plus className="h-4 w-4" />
                    </button>
                  </TooltipTrigger>
                  <TooltipContent side="bottom">New workspace</TooltipContent>
                </Tooltip>
              </SidebarRowRight>
            )}
          </SidebarRow>
        </CollapsibleTrigger>
      </SidebarMenuItem>
      <AnimatePresence initial={false}>
        {!isCollapsed && (
          <m.ul
            key="workspace-list"
            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
            className="flex min-w-0 flex-col overflow-hidden"
          >
            {sidebarExpanded && (
              <RepositoryWorkspaceList
                repository={repository}
                isDeus={isDeus}
                selectedWorkspaceId={selectedWorkspaceId}
                unreadWorkspaceIds={unreadWorkspaceIds}
                diffStatsMap={diffStatsMap}
                reduceMotion={reduceMotion}
                onNewWorkspace={onNewWorkspace}
                onWorkspaceClick={onWorkspaceClick}
                onArchive={onArchive}
                onStatusChange={onStatusChange}
              />
            )}
          </m.ul>
        )}
      </AnimatePresence>
    </Collapsible>
  );
}

// ── Inner list with stale-workspace collapsing ───────────────────────────

interface RepositoryWorkspaceListProps {
  repository: RepoGroup;
  isDeus: boolean;
  selectedWorkspaceId: string | null;
  unreadWorkspaceIds?: Set<string>;
  diffStatsMap?: Record<string, DiffStats>;
  reduceMotion: boolean | null;
  onNewWorkspace: (repoId?: string) => void;
  onWorkspaceClick: (workspace: Workspace) => void;
  onArchive?: (workspaceId: string) => void;
  onStatusChange?: (workspaceId: string, status: WorkspaceStatus) => void;
}

function RepositoryWorkspaceList({
  repository,
  isDeus,
  selectedWorkspaceId,
  unreadWorkspaceIds,
  diffStatsMap,
  reduceMotion,
  onNewWorkspace,
  onWorkspaceClick,
  onArchive,
  onStatusChange,
}: RepositoryWorkspaceListProps) {
  const isExpanded = useSidebarStore((s) => s.expandedOldWorkspaces.has(repository.repo_id));
  const toggleOldWorkspaces = useSidebarStore((s) => s.toggleOldWorkspaces);

  const sortedWorkspaces = sortByStatusPriority(
    repository.workspaces.filter((w) => w.state !== "archived"),
    unreadWorkspaceIds
  );

  const [visible, stale] = splitByRecency(sortedWorkspaces, selectedWorkspaceId);
  const hasStale = stale.length > 0;
  const displayedWorkspaces = hasStale && !isExpanded ? visible : sortedWorkspaces;

  return (
    <>
      {isDeus && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.22,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : 0.02,
          }}
        >
          <DeusRepositoryBanner onNewWorkspace={() => onNewWorkspace(repository.repo_id)} />
        </m.li>
      )}

      {sortedWorkspaces.length === 0 && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.18,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : 0.03,
          }}
        >
          <SidebarRow
            variant="action"
            asChild
            onClick={() => onNewWorkspace(repository.repo_id)}
            className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
          >
            <button type="button">
              <SidebarRowMain>
                <SidebarRowIconSlot>
                  <Plus className="h-4 w-4" />
                </SidebarRowIconSlot>
                <span className="font-normal">New workspace</span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}

      {displayedWorkspaces.map((workspace, index) => (
        <m.li
          key={workspace.id}
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.18,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
          }}
        >
          <WorkspaceItem
            workspace={workspace}
            isActive={workspace.id === selectedWorkspaceId}
            diffStats={diffStatsMap?.[workspace.id]}
            onClick={onWorkspaceClick}
            onArchive={onArchive}
            onStatusChange={onStatusChange}
          />
        </m.li>
      ))}

      {hasStale && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.15, ease: [0.165, 0.84, 0.44, 1] }}
        >
          <SidebarRow
            variant="action"
            asChild
            className="text-text-muted hover:text-text-secondary w-full text-left"
          >
            <button type="button" onClick={() => toggleOldWorkspaces(repository.repo_id)}>
              <SidebarRowMain>
                <SidebarRowIconSlot>
                  <ChevronDown
                    className={cn(
                      "h-3.5 w-3.5 transition-transform duration-150",
                      isExpanded && "rotate-180"
                    )}
                  />
                </SidebarRowIconSlot>
                <span className="text-xs font-medium">
                  {isExpanded ? "Show less" : `Show ${stale.length} more`}
                </span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}
    </>
  );
}

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cn } from "@/shared/lib/utils";

type SidebarRowVariant = "repo" | "workspace" | "action";

interface SidebarRowProps extends React.ComponentProps<"div"> {
  variant?: SidebarRowVariant;
  isActive?: boolean;
  asChild?: boolean;
}

/**
 * SidebarRow — V2: Jony Ive
 *
 * Active: bg-selection (warm white in light, elevated in dark)
 * Hover: 4% foreground overlay (barely visible, theme-agnostic)
 * Padding: repo=8px 12px, workspace/action=10px 12px
 * Workspace items use same left padding as repo — alignment comes from 20x20 icon wrappers.
 */
const rowVariants: Record<SidebarRowVariant, string> = {
  repo: "py-1 px-3",
  workspace: "py-2.5 px-3",
  action: "py-2.5 px-3",
};

export function SidebarRow({
  variant = "repo",
  isActive = false,
  asChild = false,
  className,
  ...props
}: SidebarRowProps) {
  const Comp = asChild ? Slot : "div";

  return (
    <Comp
      className={cn(
        "group/sidebar-row relative flex w-full items-center justify-between gap-3 rounded-lg",
        "transition-colors duration-100 ease-out",
        rowVariants[variant],
        isActive ? "bg-bg-selection" : "hover:bg-foreground/[0.04]",
        className
      )}
      {...props}
    />
  );
}

interface SidebarRowMainProps extends React.ComponentProps<"div"> {
  asChild?: boolean;
}

export function SidebarRowMain({ asChild = false, className, ...props }: SidebarRowMainProps) {
  const Comp = asChild ? Slot : "div";

  return <Comp className={cn("flex min-w-0 flex-1 items-center gap-2", className)} {...props} />;
}

export function SidebarRowIconSlot({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      className={cn("flex h-5 w-5 shrink-0 items-center justify-center", className)}
      {...props}
    />
  );
}

export function SidebarRowRight({ className, ...props }: React.ComponentProps<"div">) {
  return <div className={cn("flex shrink-0 items-center gap-2", className)} {...props} />;
}

import * as React from "react";
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  MouseSensor,
  TouchSensor,
  useSensor,
  useSensors,
  DragEndEvent,
} from "@dnd-kit/core";
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { FolderOpen } from "lucide-react";
import { Sidebar, SidebarContent, SidebarMenu, useSidebar } from "@/components/ui/sidebar";
import { useUIStore } from "@/shared/stores/uiStore";
import { useSidebarStore } from "../store/sidebarStore";
import type { AppSidebarProps } from "../model/types";
import { DraggableRepository } from "./DraggableRepository";
import { SidebarHeader } from "./SidebarHeader";
import { SidebarFooter } from "./SidebarFooter";

export function AppSidebar({
  repositories,
  selectedWorkspaceId,
  onWorkspaceClick,
  onNewWorkspace,
  onNewWorkspaceFromGitHub,
  onAddRepository,
  onCloneRepository,
  onArchive,
  onStatusChange,
  onNewSession,
  diffStatsMap,
  profile = { username: "User" },
}: AppSidebarProps) {
  const { state, hoverOpen, toggleSidebar, isMobile, setOpenMobile } = useSidebar();
  const openSettings = useUIStore((s) => s.openSettings);
  const collapsedRepos = useSidebarStore((s) => s.collapsedRepos);
  const toggleRepoCollapse = useSidebarStore((s) => s.toggleRepoCollapse);
  const repositoryOrder = useSidebarStore((s) => s.repositoryOrder);
  const setRepositoryOrder = useSidebarStore((s) => s.setRepositoryOrder);
  const reorderRepositories = useSidebarStore((s) => s.reorderRepositories);

  const isExpanded = state === "expanded" || hoverOpen;

  // On mobile, close the sidebar sheet after selecting a workspace
  const handleWorkspaceClick = React.useCallback(
    (workspace: Parameters<typeof onWorkspaceClick>[0]) => {
      onWorkspaceClick(workspace);
      if (isMobile) setOpenMobile(false);
    },
    [onWorkspaceClick, isMobile, setOpenMobile]
  );

  // User's drag-drop order is the final word.
  // Status is shown visually (badges, colors) — not by re-sorting after drag.
  const orderedRepositories = React.useMemo(
    () => reorderRepositories(repositories),
    [repositories, repositoryOrder, reorderRepositories]
  );

  // Mouse: 5px distance differentiates click from drag
  // Touch: 250ms long-press required before drag activates (allows normal scrolling)
  const sensors = useSensors(
    useSensor(MouseSensor, { activationConstraint: { distance: 5 } }),
    useSensor(TouchSensor, { activationConstraint: { delay: 250, tolerance: 5 } }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  /**
   * Handle drag end - reorder repositories
   */
  function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event;

    if (!over || active.id === over.id) {
      return;
    }

    const oldIndex = orderedRepositories.findIndex((r) => r.repo_id === active.id);
    const newIndex = orderedRepositories.findIndex((r) => r.repo_id === over.id);

    if (oldIndex === -1 || newIndex === -1) {
      return;
    }

    // Reorder array
    const reordered = arrayMove(orderedRepositories, oldIndex, newIndex);

    // Save new order to store
    const newOrder = reordered.map((r) => r.repo_id);
    setRepositoryOrder(newOrder);
  }

  return (
    <Sidebar variant="inset" collapsible="offcanvas" className="p-0">
      <SidebarHeader
        profile={profile}
        onOpenSettings={openSettings}
        onToggleSidebar={toggleSidebar}
        onNewSession={onNewSession}
        isExpanded={isExpanded}
      />

      {/* Repositories List or Empty State */}
      {repositories.length === 0 ? (
        <SidebarContent className="flex h-full items-center justify-center">
          <div className="flex flex-col items-center gap-3 px-6 text-center">
            <FolderOpen className="text-text-muted/30 h-10 w-10" strokeWidth={1.5} />
            <div className="space-y-1">
              <p className="text-text-secondary text-sm font-medium">No projects yet</p>
              <p className="text-text-muted text-xs">Add your first project to get started</p>
            </div>
          </div>
        </SidebarContent>
      ) : (
        <SidebarContent className="scrollbar-hidden">
          <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragEnd={handleDragEnd}
          >
            <SortableContext
              items={orderedRepositories.map((r) => r.repo_id)}
              strategy={verticalListSortingStrategy}
            >
              <SidebarMenu className="gap-2.5 px-1.5 py-2">
                {orderedRepositories.map((repo) => (
                  <DraggableRepository
                    key={repo.repo_id}
                    repository={repo}
                    isCollapsed={collapsedRepos.has(repo.repo_id)}
                    selectedWorkspaceId={selectedWorkspaceId}
                    onToggleCollapse={() => toggleRepoCollapse(repo.repo_id)}
                    onWorkspaceClick={handleWorkspaceClick}
