                    )}
                  />
                </SidebarRowIconSlot>
                <span className="text-xs font-medium">
                  {isExpanded ? "Show less" : `Show ${stale.length} more`}
                </span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}
    </>
  );
}

